<?php
$row = is_array($row ?? null) ? $row : [];
$lines = is_array($lines ?? null) ? $lines : [];
$money = static function ($value): string { return 'Rp ' . number_format((float)$value, 0, ',', '.'); };
$dt = static function ($value): string { $time = $value ? strtotime((string)$value) : false; return $time ? date('d M Y H:i', $time) : '-'; };
$this->load->view('pos/_report_styles');
?>

<div class="container-xxl py-3"><div class="pos-report-shell"><div class="pos-report-hero mb-3"><div class="d-flex flex-wrap justify-content-between gap-3"><div><div class="pos-report-title">Detail Pembayaran POS</div><p class="pos-report-copy mb-0">Rincian satu dokumen pembayaran lengkap dengan metode bayar dan referensi transaksinya.</p></div><a href="<?php echo site_url('pos/reports/payments'); ?>" class="btn btn-outline-secondary">Kembali</a></div></div><?php $this->load->view('pos/_report_nav', ['report_nav_active' => 'payment']); ?><div class="row g-3 mb-3"><div class="col-lg-5"><div class="pos-report-section p-3 h-100"><div class="pos-report-kv"><strong>Payment</strong><span><?php echo html_escape((string)($row['payment_no'] ?? '-')); ?></span><strong>Order</strong><span><?php echo html_escape((string)($row['order_no'] ?? '-')); ?></span><strong>Member</strong><span><?php echo html_escape((string)($row['member_name'] ?? '-')); ?><?php echo !empty($row['member_no']) ? ' · ' . html_escape((string)$row['member_no']) : ''; ?></span><strong>Outlet</strong><span><?php echo html_escape((string)($row['outlet_name'] ?? '-')); ?></span><strong>Kasir</strong><span><?php echo html_escape((string)($row['cashier_name'] ?? '-')); ?></span><strong>Status</strong><span><?php echo html_escape((string)($row['payment_status'] ?? '-')); ?></span><strong>Tipe</strong><span><?php echo html_escape((string)($row['payment_type'] ?? '-')); ?></span><strong>Paid At</strong><span><?php echo html_escape($dt($row['paid_at'] ?? null)); ?></span><strong>Catatan</strong><span><?php echo html_escape((string)($row['notes'] ?? '-')); ?></span></div></div></div><div class="col-lg-7"><div class="row g-3"><div class="col-md-4"><div class="pos-report-card"><div class="pos-report-card-label">Gross</div><div class="pos-report-card-value"><?php echo $money($row['gross_amount'] ?? 0); ?></div><div class="pos-report-card-note">Nilai sebelum potongan.</div></div></div><div class="col-md-4"><div class="pos-report-card"><div class="pos-report-card-label">Net</div><div class="pos-report-card-value"><?php echo $money($row['net_amount'] ?? 0); ?></div><div class="pos-report-card-note">Nilai akhir payment.</div></div></div><div class="col-md-4"><div class="pos-report-card"><div class="pos-report-card-label">Change</div><div class="pos-report-card-value"><?php echo $money($row['change_amount'] ?? 0); ?></div><div class="pos-report-card-note">Kembalian yang tercatat.</div></div></div></div></div></div><div class="pos-report-section p-3"><h5 class="mb-3">Breakdown Pembayaran</h5><div class="pos-report-table-wrap"><div class="table-responsive"><table class="table table-sm align-middle mb-0 pos-report-table"><thead><tr><th>Line</th><th>Metode</th><th>Reference</th><th>Gateway</th><th>Akun</th><th class="text-end">Amount</th><th>Received At</th><th>Status</th></tr></thead><tbody><?php if (empty($lines)): ?><tr><td colspan="8" class="text-center pos-report-empty">Belum ada line pembayaran.</td></tr><?php else: ?><?php foreach ($lines as $line): ?><tr><td><?php echo (int)($line['line_no'] ?? 0); ?></td><td><div><?php echo html_escape((string)($line['method_name'] ?? '-')); ?></div><div class="pos-report-meta"><?php echo html_escape((string)($line['method_type'] ?? '-')); ?></div></td><td><?php echo html_escape((string)($line['reference_no'] ?? '-')); ?></td><td><?php echo html_escape((string)($line['gateway_txn_id'] ?? '-')); ?></td><td><?php echo html_escape((string)($line['company_account_name'] ?? $line['company_bank_name'] ?? '-')); ?></td><td class="text-end fw-semibold"><?php echo $money($line['amount'] ?? 0); ?></td><td><?php echo html_escape($dt($line['received_at'] ?? null)); ?></td><td><?php echo html_escape((string)($line['status'] ?? '-')); ?></td></tr><?php endforeach; ?><?php endif; ?></tbody></table></div></div></div></div></div>